from sympy import Integer, Rational, divisors, totient, ceiling, floor
def anum(n: int) -> int:
    if n < 1:
        return 0
    n = Integer(n)
    term1 = sum(2**(n // d) * totient(d) for d in divisors(n)) // (2 * n)
    term2 = floor(2**(n - 2) + 2**ceiling(n / 2 - 2) - Rational(n + 1, 2))
    return int(term1 + term2)

